tlDataChunk*
tlMultiControllerChunk16::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case P3D_MULTI_CONTROLLER_TRACKS:
        dch = new tlMultiControllerTracksChunk16(&ch);
        break;
    case P3D_MULTI_CONTROLLER_TRACK:
        dch = new tlMultiControllerTrackChunk16(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

