tlMultiControllerTracksChunk16::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                numtracks = tmp;
                return true;
            }
            return false;
        }
        case 1:
            return false;
        default:
            return false;
    }
}

bool 
tlMultiControllerTracksChunk16::SetFieldArrayValue(int fieldIndex, int arrayIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
            return false;

        case 1:
            return tracks[arrayIndex].SetFieldValue(new_val);

        default:
            return false;
    }
}

