// tlMultiControllerTrackChunk16

int tlMultiControllerTrackChunk16::sortPriority = -1;

tlMultiControllerTrackChunk16::tlMultiControllerTrackChunk16()
{
    Init();
}

tlMultiControllerTrackChunk16::tlMultiControllerTrackChunk16(const tlMultiControllerTrackChunk16& ch)
{
    Init();
    *this = ch;
}

tlMultiControllerTrackChunk16::~tlMultiControllerTrackChunk16()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlMultiControllerTrackChunk16::tlMultiControllerTrackChunk16(tlReadChunk16* ch)
{
    assert(ch->GetID() == P3D_MULTI_CONTROLLER_TRACK);
    ident = P3D_MULTI_CONTROLLER_TRACK;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    starttime = f->GetFloat();
    endtime = f->GetFloat();
    scale = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_MULTI_CONTROLLER_TRACK);
    }
}

void
tlMultiControllerTrackChunk16::Init()
{
    ident = P3D_MULTI_CONTROLLER_TRACK;
    name = NULL;
    starttime = 0.0f;
    endtime = 0.0f;
    scale = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(P3D_MULTI_CONTROLLER_TRACK);
    }
}

long 
tlMultiControllerTrackChunk16::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( starttime );
    s += sizeof( endtime );
    s += sizeof( scale );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlMultiControllerTrackChunk16&
tlMultiControllerTrackChunk16::operator=(const tlMultiControllerTrackChunk16& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    starttime = a.starttime;
    endtime = a.endtime;
    scale = a.scale;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlMultiControllerTrackChunk16::operator==(const tlDataChunk& a)
{

    const tlMultiControllerTrackChunk16* aptr = dynamic_cast<const tlMultiControllerTrackChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(starttime == aptr->starttime))
    {
        return false;
    }
    if(!(endtime == aptr->endtime))
    {
        return false;
    }
    if(!(scale == aptr->scale))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlMultiControllerTrackChunk16::NameCompare(const tlDataChunk& a)
{

    const tlMultiControllerTrackChunk16* aptr = dynamic_cast<const tlMultiControllerTrackChunk16*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlMultiControllerTrackChunk16::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlMultiControllerTrackChunk16(ch);
    return dtCh;
}

void
tlMultiControllerTrackChunk16::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(name);
        f->PutFloat(starttime);
        f->PutFloat(endtime);
        f->PutFloat(scale);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlMultiControllerTrackChunk16::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlMultiControllerTrackChunk16 (%4x)\n",indent,"",(int) ident);
    printf("%*s  Name      = \"%s\"\n",indent,"",name);
    printf("%*s  StartTime = %f\n",indent,"",starttime);
    printf("%*s  EndTime   = %f\n",indent,"",endtime);
    printf("%*s  Scale     = %f\n",indent,"",scale);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlMultiControllerTrackChunk16::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Name     \n",indent,"",name);
    printf("%*s  float %12f # StartTime\n",indent,"",starttime);
    printf("%*s  float %12f # EndTime  \n",indent,"",endtime);
    printf("%*s  float %12f # Scale    \n",indent,"",scale);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

